urlset:
{%- for file in pages -%}
    {% if not file.page.is_link and (file.page.abs_url or file.page.canonical_url) and not file.src_uri.startswith('uat/') %}

         {% if file.page.canonical_url %}{{ file.page.canonical_url|e }}{% else %}{{ file.page.abs_url|e }}{% endif %}
         {% if file.page.update_date %}{{file.page.update_date}}{% endif %}

    {%- endif -%}
{% endfor %}
